FROM (VALUES
  ('brokertur-nedvizhimost-kaliningrad', 'Брокер-тур недвижимость', 'Калининград', 'Эксклюзивный штурм топовых новостроек Калининграда для профессионалов рынка недвижимости! Стратегический нетворкинг! Прямые контакты с застройщиками!', 500, '/images/tours/kaliningrad.jpg', $seedjson$[{"id":1,"time":"9:15","title":"Сбор – Radisson Blu Hotel Калининград, пл. Победы, 10","description":""},{"id":2,"time":"9:30","title":"Отправление автобуса","description":""},{"id":3,"time":"10:00 - 10:45","title":"ЖК Включи","description":"Комплексная застройка, состоящая из монолитно-кирпичных зданий. Застройщиком спроектированы квартиры с различными планировками. Выполняется чистовая и предчистовая отделка. Благоустройство прилегающей территории включает в себя организацию детских игровых и спортивных площадок, гостевой автостоянки, а также озеленение. В шаговой доступности детские сады, школы, продуктовые магазины, остановки общественного транспорта"},{"id":4,"time":"11:00 - 11:45","title":"ЖК Легенды Девау","description":"Новый жилой квартал Комфорт-класса «Легенды Девау» расположился в самом сердце «Девау» - района с богатым историческим и культурным наследием, прямо возле знаменитого на весь мир аэродрома, которому суждено в ближайшем будущем стать самым футуристическим экопространством Калининграда, великолепным ландшафтным и тематическим парком"},{"id":4,"time":"12:00 - 12:45","title":"ЖК Русская Европа","description":"Уникальный НЕ-спальный микрорайон экокомфорт-класса, сомасштабно человеку с полноценно жилой средой. Здесь хорошо организованы жилые кварталы и центральные общественные зоны. Вся застройка отвечает трём ключевым принципам: разнообразие типов жилья, общественных пространств и социальной инфраструктуры."},{"id":5,"time":"12:45 - 13:45","title":"Обед","description":""},{"id":6,"time":"14:00 - 14:45","title":"ЖК Фридланд","description":"Ганзейские мотивы в сочетании с фахверком в современном воплощении удачно вписываются в существующее окружение комплекса. Наш подход — максимально сохранить историю, но в то же время обеспечить связь с современностью. И благодаря разнообразию фактур и богатству архитектурной обработки авторам проекта удалось придать внешнему облику комплекса изысканность и долговечность. Тёмная, частично скатная кровля визуально снижает этажность комплекса. Вентилируемый фасад вертикально разделен на отдельные части, представляющие собой симбиоз различных фактур и покрытий. Проект включает благоустройство прилегающей территории: тротуары, замощенные плиткой."},{"id":7,"time":"15:15 - 15:45","title":"ЖК Кант Сити","description":"204 просторные и функциональные квартиры. Всего 7 этажей. Верхние квартиры – видовые двухуровневые пентхаусы. Подземный паркинг (с заботой об автомобилях)"},{"id":8,"time":"16:00 - 16:45","title":"Многофункциональный центр «БЭЛФОРТ»","description":"В исторической части города Калининграда возводится многофункциональный спортивно-деловой комплекс с теннисным центром международного уровня, не имеющего аналогов в России. Цель проекта – создание удобной и функциональной городской среды с физкультурно-оздоровительным центром, современной гостиницей и бизнес-центром, предприятиями общественного питания, магазинами профессионального спортивного инвентаря ведущих мировых марок."},{"id":9,"time":"17:00 - 17:30","title":"ЖК Теодора Кроне","description":"Современный жилой квартал комфорт-класса, расположенный в одном из самых зеленых и спокойных районов Калининграда. Рядом с ЖК есть выезд на удобные транспортные развязки, ведущие в центр города, на Сельму и в сторону побережья. Одно из главных преимуществ комплекса – непосредственная близость к парку им. Теодора Кроне, массивной лесопарковой зоне, что создает удивительный баланс жизни в окружении природы и комфорта городской среды."}]$seedjson$, 0),
  ('brokertur-nedvizhimost-poberezhe', 'Брокер-тур недвижимость', 'Побережье', 'Тур для тех, кто продает не квартиры,, а мечты о море! Прямые договоры с застройщиками квартир на побережье!', 500, '/images/tours/poberezhe.jpg', $seedjson$[{"id":1,"time":"9:15","title":"Сбор – Radisson Blu Hotel Калининград, пл. Победы, 10","description":""},{"id":2,"time":"9:30","title":"Отправление автобуса","description":""},{"id":3,"time":"10:30 - 11:00","title":"Апарт комплекс Престиж парк, г. Балтийск","description":"Два современных четырехэтажных дома комфорт-класса. Объект расположен в центре города Балтийска, на берегу Балтийского моря. Комплекс находится на улице Чехова, в нескольких минутах неспешной прогулки от пляжа. Из окон апартаментов открываются невероятные виды на морское побережье. Рядом великолепный зеленый парк."},{"id":4,"time":"11:15 - 12:00","title":"ЖК Балтийская гавань","description":"Жилой комплекс находится в центре города Балтийска, на берегу Балтийского моря. Класс энергоэффективности дома А++ считается самым высоким. В таких домах экономится до 60% ресурсов. Проектом предусмотрена велосипедная дорожка, обеспечивающая прямой доступ от въезда на территорию жилого комплекса до места хранения велосипедов около входов в жилые дома. Детская и спортивная площадки. Места для отдыха."},{"id":5,"time":"12:45 - 13:45","title":"Обед","description":""},{"id":6,"time":"14:00 - 14:30","title":"ЖК Лесная Сказка, Светлогорск","description":"Жилой комплекс бизнес-класса, в котором органично переплетаются безопасность, удобство проживания и экологичное окружение. ЖК «Лесная сказка» включает 8 строений высотностью от 5 до 7 этажей с различными вариантами планировок, которые подойдут как молодым семьям, так и ценителям спокойной атмосферы."},{"id":7,"time":"14:45 - 15:30","title":"Апарт-отель «Лазурь» (СК МПК), Светлогорск","description":"Там, где море встречается с небом"},{"id":8,"time":"15:40 - 15:50","title":"Апартаменты «ELEMENT», г. Светлогорск","description":"Cреда для жизни и отдыха, созданная для восстановления сил и внутреннего баланса. Здесь каждый найдет себя и то, что ему необходимо для полноценного отдыха"},{"id":9,"time":"15:50 - 16:30","title":"Гостиничный комплекс Русь","description":"Элитные апартаменты с уровнем обслуживания 5 звездочного отеля на побережье Балтийского моря"},{"id":10,"time":"17:00 - 17:30","title":"ЖК «Венецианский квартал»","description":"В Зеленоградске, на улице Тургенева, расположился жилой комплекс «Венецианский квартал». Здесь, среди зелени лесов и зеркальной глади озера."},{"id":11,"time":"17:40 - 18:00","title":"Апартаменты «Грани», Зеленоградск","description":"Пятиэтажное здание с благоустроенной территорией. Авторское архитектурное решение в сочетании с высококачественными материалами отвечают всем требованиям современного человека к недвижимости комфорт-класса. Каждая секция оснащена лифтом и продуманными общественными пространствами, которые обеспечивают беспрепятственный доступ для маломобильных групп населения."}]$seedjson$, 10),
  ('brokertur-nedvizhimost-premium', 'Брокер-тур недвижимость', 'Премиум', 'Специальный Брокер Тур откроет участникам доступ к ключевым инвестиционным объектам премиального сегмента области.', 500, '/images/tours/premium.jpg', $seedjson$[{"id":1,"time":"9:15","title":"Сбор – Radisson Blu Hotel Калининград, пл. Победы, 10","description":""},{"id":2,"time":"9:30","title":"Отправление автобуса","description":""},{"id":3,"time":"10:00 - 10:45","title":"ЖК Рыбная Деревня","description":"Квартиры с ремонтом или White box. Островок приватности в самом сердце Калининграда"},{"id":4,"time":"11:00 - 11:45","title":"ЖК Фридланд","description":"Ганзейские мотивы в сочетании с фахверком в современном воплощении удачно вписываются в существующее окружение комплекса. Наш подход — максимально сохранить историю, но в то же время обеспечить связь с современностью. И благодаря разнообразию фактур и богатству архитектурной обработки авторам проекта удалось придать внешнему облику комплекса изысканность и долговечность. Тёмная, частично скатная кровля визуально снижает этажность комплекса. Вентилируемый фасад вертикально разделен на отдельные части, представляющие собой симбиоз различных фактур и покрытий. Проект включает благоустройство прилегающей территории: тротуары, замощенные плиткой"},{"id":5,"time":"12:30 - 13:00","title":"Princesse Royal","description":"Апартаменты с ремонтом на променаде с видом на море. Лаконичный архитектурный проект мультифункционального отеля"},{"id":6,"time":"12:45 - 13:45","title":"Обед","description":""},{"id":7,"time":"14:15 - 15:45","title":"ЖК «Атлантис»","description":"Находится на побережье Балтийского моря, в курортном городе федерального значения - Зеленоградске. Для удобства покупателей часть квартир продается с готовым дизайнерским ремонтом в различных стилевых решениях. Также во всех домах предполагается решение по ремонту под ключ в соответствии с выбором покупателя."},{"id":8,"time":"16:30 - 17:30","title":"Гостиничный комплекс Русь, Светлогорск","description":"Элитные апартаменты с уровнем обслуживания 5 звездочного отеля на побережье Балтийского моря."},{"id":9,"time":"17:30 - 18:00","title":"Апартаменты «ELEMENT», Светлогорск","description":"Среда для жизни и отдыха, созданная для восстановления сил и внутреннего баланса. Здесь каждый найдет себя и то, что ему необходимо для полноценного отдыха"},{"id":10,"time":"","title":"ОТДЫХ В Баден СПА – г. Светлогорск","description":""}]$seedjson$, 20),
  ('brokertur-nedvizhimost-zagorodnaya-mechta', 'Брокер-тур недвижимость', 'Загородная мечта', 'Специальный Брокер Тур по коттеджным поселкам.', 500, '/images/tours/mechta.jpg', $seedjson$[{"id":1,"time":"9:15","title":"Сбор – Radisson Blu Hotel Калининград, пл. Победы, 10","description":""},{"id":2,"time":"9:30","title":"Отправление автобуса","description":""},{"id":3,"time":"10:45 - 11:45","title":"Коттеджный поселок Рублувочка Юг","description":"Концепция идеально подходит тем, кто ищет баланс комфорта и природы, предлагая при этом роскошные условия для жизни вдали от городской суеты"},{"id":4,"time":"12:00 - 13:00","title":"Коттеджный поселок «Новая Рублевочка»","description":"В гармонии с природой: коттеджный поселок «Новая Рублевочка» создан для тех, кто ценит современный комфорт, безопасность и чистый воздух в окружении живописных пейзажей. Это идеальный уголок спокойствия и благополучия"},{"id":5,"time":"13:10 - 14:10","title":"Обед","description":""},{"id":7,"time":"14:15 - 15:45","title":"ЖК Холмы","description":"Будет выполнен в единой европейской архитектурной концепции, это малоэтажные задуман как проект комплексной застройки из 30 четырехэтажных домов на территории в 20 гектар. Реализуется поквартальный принцип застройки - 30 домов с автономным газовым отоплением"},{"id":8,"time":"16:30 - 18:00","title":"Прогулка по Зеленоградску","description":""}]$seedjson$, 30)
